    ('30000000-0000-0000-0000-000000000012', 4, '3일 전에 읽었는데 여운이 길게 남네요.', 120, 40, '2026-03-06 10:00:00+09', '2026-03-06 10:00:00+09', NULL, '20000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000001'),
    ('30000000-0000-0000-0000-000000000013', 5, '최근 읽은 책 중 단연 최고입니다.', 95, 20, '2026-03-06 11:30:00+09', '2026-03-06 11:30:00+09', NULL, '20000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000005'),
