    ('30000000-0000-0000-0000-000000000018', 4, '분량이 꽤 되지만 몰입감이 좋습니다.', 60, 15, '2026-02-23 11:10:00+09', '2026-02-23 11:10:00+09', NULL, '20000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000005'),
    ('30000000-0000-0000-0000-000000000019', 3, '결말이 조금 흐지부지해서 별 3개 줍니다.', 25, 5, '2026-02-23 13:40:00+09', '2026-02-23 13:40:00+09', NULL, '20000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000002'),
    ('30000000-0000-0000-0000-000000000020', 5, '올해 최고의 소설이 아닐까 싶네요.', 110, 35, '2026-02-23 17:05:00+09', '2026-02-23 17:05:00+09', NULL, '20000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000003'),
